import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.io.IOException;

public class CSVFormatTest {

    @Test
    public void testPrintAndEscape() throws IOException {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '\"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        CSVFormat spyFormat = Mockito.spy(csvFormat);
        CharSequence value = "abc,def";
        int offset = 0;
        int len = value.length();
        Appendable out = new StringWriter();

        // When
        try {
            spyFormat.printAndEscape(value, offset, len, out);
        } catch (IOException e) {
            fail("IOException should not be thrown");
        }

        // Then
        assertEquals("abc,\"def\"", out.toString());
        Mockito.verify(spyFormat, Mockito.times(1)).printAndEscape(value, offset, len, out);
    }
}
